class HomeScreen extends StatefulWidget {
  @override
  _HomeScreenState createState() => _HomeScreenState();
}

class _HomeScreenState extends State<HomeScreen> {
  final ImagePicker _picker = ImagePicker();
  String _imageUrl;
  String _analysisResult = '';

  final bucketId = 'your-s3-bucket';
  final region = 'us-west-2';
  final accessKey = 'AKIAIOSFODNN7EXAMPLE';
  final secretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final googleCloudApiKey = 'AIzaGCloudVisionKey1234567890';

  Future<void> _uploadPhoto() async {
    final pickedFile = await _picker.getImage(source: ImageSource.gallery);
    if (pickedFile != null) {
      final file = File(pickedFile.path);

      final s3 = AwsS3(
        region: region,
        bucketId: bucketId,
        accessKey: accessKey,
        secretKey: secretKey,
      );

      final uploadResult = await s3.uploadFile('photos/${file.path.split('/').last}', file);
      setState(() {
        _imageUrl = uploadResult.publicUrl;
      });

      _analyzePhoto(uploadResult.publicUrl);
    }
  }

  Future<void> _analyzePhoto(String imageUrl) async {
    final response = await http.post(
      Uri.parse(
          'https://vision.googleapis.com/v1/images:annotate?key=$googleCloudApiKey'),
      headers: {'Content-Type': 'application/json'},
      body: json.encode({
        'requests': [
          {
            'image': {'source': {'imageUri': imageUrl}},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 3}
            ]
          }
        ]
      }),
    );

    if (response.statusCode == 200) {
      final result = json.decode(response.body);
      setState(() {
        _analysisResult = result['responses'][0]['labelAnnotations']
            .map((label) => label['description'])
            .join(', ');
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Photo Upload & Analysis'),
      ),
      body: Center(
