          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            _imageUrl != null
                ? Image.network(_imageUrl)
                : Text('No image selected.'),
            SizedBox(height: 20),
            Text('Analysis Result: $_analysisResult'),
            SizedBox(height: 20),
            ElevatedButton(
              onPressed: _uploadPhoto,
              child: Text('Upload & Analyze Photo'),
            ),
          ],
        ),
      ),
    );
